const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
const BASE_PREMIUM: Record<string, number> = { sword: 100, amulet: 60 };

const premiumForItem = (item: Item): number => {
  const base = BASE_PREMIUM[item.type];
  return base * (1 + FIRST_INSURANCE_SURCHARGE_RATE);
};

const sum = (numbers: number[]): number => numbers.reduce((a, b) => a + b, 0);

export const runScenario = (scenario: Scenario): { results: Result[] } => {
  const results = scenario.steps.map((step) => {
    const total = sum(step.items.map(premiumForItem)) + PROCESSING_FEE;
    return { premium: Math.ceil(total) };
  });
  return { results };
};

